@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
  color: #05042E;
  padding: 0.75rem;
}

.grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.75rem;
}

.card {
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 10px;
  overflow: hidden;
}

.card-header {
  padding: 14px 16px;
  display: flex;
  align-items: center;
  gap: 8px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
}

.card-header-icon {
  width: 26px;
  height: 26px;
  border-radius: 8px;
  background: rgba(5, 4, 46, 0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #05042E;
  font-size: 13px;
  flex-shrink: 0;
}

.card-title {
  font-size: 10px;
  font-weight: 700;
  color: #05042E;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  flex: 1;
}

.card-body {
  padding: 1rem;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.field-group {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.field-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
}

.field-group.full {
  grid-column: 1/-1;
}

label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

input, select, textarea {
  font-size: 13px;
  font-family: "Figtree", sans-serif;
  font-weight: 600;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 6px;
  padding: 7px 10px;
  color: #05042E;
  outline: none;
  width: 100%;
  background: #fff;
}

input:focus, select:focus, textarea:focus {
  border-color: #469BC0;
}

input[readonly] {
  background: rgba(5, 4, 46, 0.04);
  color: #888780;
}

textarea {
  resize: vertical;
  min-height: 60px;
}

input::placeholder, textarea::placeholder {
  color: #b0aeb8;
  font-weight: 400;
}

.section-title {
  font-size: 10px;
  font-weight: 700;
  color: #469BC0;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 0.75rem;
  display: flex;
  align-items: center;
  gap: 6px;
}

.section-title::after {
  content: "";
  flex: 1;
  height: 0.5px;
  background: rgba(0, 0, 0, 0.08);
}

.compliance-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 8px;
  margin-bottom: 0.75rem;
}

.compliance-item {
  background: rgba(5, 4, 46, 0.04);
  border-radius: 8px;
  padding: 8px 10px;
}

.compliance-label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 3px;
}

.compliance-value {
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
}

.compliance-alert {
  font-size: 11px;
  font-weight: 600;
  padding: 8px 12px;
  border-radius: 6px;
  background: #FAEEDA;
  color: #633806;
  margin-bottom: 0.75rem;
  display: none;
}

.compliance-alert.show {
  display: block;
}

.site-table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 4px;
}

.site-table th {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  padding: 6px 8px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
  text-align: left;
}

.site-table td {
  padding: 9px 8px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
  cursor: pointer;
}

.site-table tr:last-child td {
  border-bottom: none;
}

.site-table tr:hover td {
  background: rgba(5, 4, 46, 0.04);
}

.site-table tr.selected td {
  background: rgba(163, 232, 81, 0.18);
}

.site-hint {
  font-size: 11px;
  font-weight: 600;
  color: #888780;
  margin-top: 4px;
}

.selected-site {
  background: rgba(5, 4, 46, 0.04);
  border-radius: 8px;
  padding: 10px 12px;
  margin-top: 8px;
  display: none;
}

.selected-site.show {
  display: block;
}

.selected-site-title {
  font-size: 10px;
  font-weight: 700;
  color: #469BC0;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 6px;
}

.selected-site-addr {
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
}

.selected-site-contact {
  font-size: 11px;
  font-weight: 600;
  color: #888780;
  margin-top: 2px;
}

.contact-avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: rgba(5, 4, 46, 0.1);
  color: #05042E;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  font-weight: 700;
  flex-shrink: 0;
}

.contact-row {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 8px;
}

.contact-name {
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
}

.contact-sub {
  font-size: 11px;
  font-weight: 600;
  color: #888780;
}

.contact-detail {
  font-size: 11px;
  font-weight: 600;
  color: #888780;
  margin-top: 4px;
}

.contact-detail strong {
  color: #888780;
  font-weight: 700;
  letter-spacing: 0.05em;
}

.items-table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 4px;
}

.items-table th {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  padding: 6px 8px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
  text-align: left;
}

.items-table td {
  padding: 6px 8px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
  font-size: 13px;
}

.items-table tr:last-child td {
  border-bottom: none;
}

.item-input {
  font-size: 13px;
  font-weight: 600;
  border: none;
  outline: none;
  width: 100%;
  background: transparent;
  font-family: "Figtree", sans-serif;
  color: #05042E;
}

.item-qty {
  width: 60px;
  text-align: center;
}

.btn-remove {
  background: none;
  border: none;
  cursor: pointer;
  color: #991b1b;
  font-size: 14px;
  padding: 0;
}

.add-item-btn {
  font-size: 12px;
  font-weight: 700;
  color: #469BC0;
  background: none;
  border: none;
  cursor: pointer;
  font-family: "Figtree", sans-serif;
  padding: 6px 0;
  display: flex;
  align-items: center;
  gap: 4px;
}

.items-total {
  font-size: 11px;
  font-weight: 600;
  color: #888780;
  margin-top: 6px;
  display: flex;
  justify-content: space-between;
}

.items-total strong {
  color: #05042E;
}

.form-actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  margin-top: 0.75rem;
  padding: 0 0.75rem 0.75rem;
}

.btn {
  font-family: "Figtree", sans-serif;
  font-size: 12px;
  font-weight: 700;
  padding: 9px 20px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
}

.btn-primary {
  background: #A3E851;
  color: #05042E;
}

.btn-primary:hover {
  background: #5DC987;
}

.btn-cancel {
  background: #E0DFE1;
  color: #05042E;
}

.badge {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  padding: 3px 10px;
  border-radius: 20px;
  display: inline-block;
}

.survey-meta {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 8px;
  margin-bottom: 0.75rem;
}

.survey-meta-item {
  background: rgba(5, 4, 46, 0.04);
  border-radius: 8px;
  padding: 8px 10px;
}

.survey-meta-label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 3px;
}

.survey-meta-value {
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
}

.survey-flags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 0.75rem;
}

.survey-flag {
  font-size: 11px;
  font-weight: 600;
  text-transform: none;
  letter-spacing: 0;
  padding: 5px 12px;
  border-radius: 20px;
  background: #E6F1FB;
  color: #0C447C;
  white-space: normal;
  line-height: 1.4;
}

.survey-instructions {
  font-size: 11px;
  font-weight: 600;
  color: #05042E;
  background: rgba(5, 4, 46, 0.04);
  border-radius: 6px;
  padding: 8px 10px;
  margin-bottom: 0.75rem;
}

.survey-alert {
  font-size: 11px;
  font-weight: 600;
  padding: 8px 12px;
  border-radius: 6px;
  display: flex;
  align-items: center;
  gap: 6px;
}

.danger-alert {
  background: #fee2e2;
  color: #991b1b;
}

.warn-alert {
  background: #FAEEDA;
  color: #633806;
}

.toggle-row {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 2px;
}

.toggle {
  width: 40px;
  height: 22px;
  border-radius: 11px;
  border: none;
  cursor: pointer;
  position: relative;
  transition: background 0.2s;
  flex-shrink: 0;
}

.toggle.on {
  background: #5DC987;
}

.toggle.off {
  background: #E0DFE1;
}

.toggle-label {
  font-size: 12px;
  font-weight: 600;
  color: #888780;
}

.conditional {
  display: none;
  margin-top: 8px;
}

.conditional.show {
  display: block;
}

